const crypto = require('crypto');
const https = require('https');

const appId = $env.GITHUB_APP_ID;
const installationId = $env.GITHUB_INSTALLATION_ID;
const privateKeyBase64 = $env.GITHUB_PRIVATE_KEY_BASE64;
const privateKey = Buffer.from(privateKeyBase64, 'base64').toString('utf8');

const now = Math.floor(Date.now() / 1000);
const header = Buffer.from(JSON.stringify({ alg: 'RS256', typ: 'JWT' })).toString('base64url');
const payload = Buffer.from(JSON.stringify({ iat: now - 60, exp: now + 600, iss: appId })).toString('base64url');
const signature = crypto.sign('SHA256', Buffer.from(`${header}.${payload}`), privateKey).toString('base64url');
const jwt = `${header}.${payload}.${signature}`;

const token = await new Promise((resolve, reject) => {
  const req = https.request({
    hostname: 'api.github.com',
    path: `/app/installations/${installationId}/access_tokens`,
    method: 'POST',
    headers: {
      'Authorization': `Bearer ${jwt}`,
      'Accept': 'application/vnd.github+json',
      'User-Agent': 'n8n-orchestrator',
      'Content-Length': 0
    }
  }, res => {
    let body = '';
    res.on('data', c => body += c);
    res.on('end', () => {
      if (res.statusCode !== 201) reject(new Error(`GitHub token request failed: ${res.statusCode} ${body}`));
      else resolve(JSON.parse(body).token);
    });
  });
  req.on('error', reject);
  req.end();
});

return [{ json: { ...$input.first().json, githubToken: token } }];

const https = require('https');
const trigger = $('Get Installation Token').first().json.body;
const token = $('Get Installation Token').first().json.githubToken;
const gddRaw = $('Fetch GDD').first().json;
const contextRaw = $('Fetch Project Context').first().json;
const commentItems = $('Fetch Epic Comments').all().map(i => i.json);

const owner = trigger.repoOwner;
const repo = trigger.repoName;
const epicNumber = trigger.issueNumber;
const epicTitle = trigger.issueTitle;
const epicBody = trigger.issueBody;

const gdd = typeof gddRaw === 'string' ? gddRaw : JSON.stringify(gddRaw);
const projectContext = typeof contextRaw === 'string' ? contextRaw : JSON.stringify(contextRaw);
const epicComments = commentItems.map(c => `**${c.user?.login}:** ${c.body}`).join('\n\n');

// --- Shared REST helper with retry/rate-limit logic ---
function _rawRequest(method, path, body) {
  return new Promise((resolve, reject) => {
    const bodyStr = body ? JSON.stringify(body) : '';
    const headers = {
      'Authorization': `Bearer ${token}`,
      'Accept': 'application/vnd.github+json',
      'User-Agent': 'n8n-orchestrator',
      'X-GitHub-Api-Version': '2022-11-28'
    };
    if (body) {
      headers['Content-Type'] = 'application/json';
      headers['Content-Length'] = Buffer.byteLength(bodyStr);
    }
    const req = https.request({ hostname: 'api.github.com', path, method, headers }, res => {
      let d = '';
      res.on('data', c => d += c);
      res.on('end', () => {
        let parsed;
        try { parsed = JSON.parse(d); } catch(e) { parsed = d; }
        resolve({ status: res.statusCode, data: parsed, headers: res.headers });
      });
    });
    req.on('error', reject);
    if (bodyStr) req.write(bodyStr);
    req.end();
  });
}

async function githubRest(method, path, body, maxRetries = 3) {
  for (let attempt = 0; attempt <= maxRetries; attempt++) {
    const result = await _rawRequest(method, path, body);
    if (result.status >= 200 && result.status < 300) return result;
    if (result.status === 403 || result.status === 429) {
      const retryAfter = result.headers['retry-after'];
      const rateLimitReset = result.headers['x-ratelimit-reset'];
      let waitMs;
      if (retryAfter) waitMs = parseInt(retryAfter, 10) * 1000;
      else if (rateLimitReset) waitMs = Math.max((parseInt(rateLimitReset, 10) * 1000) - Date.now(), 1000);
      else waitMs = Math.pow(2, attempt) * 1000;
      if (attempt < maxRetries) { await new Promise(r => setTimeout(r, waitMs)); continue; }
    }
    if (result.status >= 400 && result.status < 500) throw new Error(`GitHub API ${result.status}: ${JSON.stringify(result.data)}`);
    if (result.status >= 500 && attempt < maxRetries) { await new Promise(r => setTimeout(r, Math.pow(2, attempt) * 1000)); continue; }
    throw new Error(`GitHub API failed after ${maxRetries + 1} attempts: ${result.status}`);
  }
}

// --- LLM call with rate limit awareness ---
async function callLLM(messages, maxRetries = 3) {
  const model = process.env.OPENROUTER_MODEL || $env.OPENROUTER_MODEL || 'stepfun/step-3.5-flash:free';
  const apiKey = process.env.OPENROUTER_API_KEY || $env.OPENROUTER_API_KEY;
  const bodyStr = JSON.stringify({ model, messages, max_tokens: 4096 });

  for (let attempt = 0; attempt <= maxRetries; attempt++) {
    const result = await new Promise((resolve, reject) => {
      const req = https.request({
        hostname: 'openrouter.ai',
        path: '/api/v1/chat/completions',
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${apiKey}`,
          'Content-Type': 'application/json',
          'Content-Length': Buffer.byteLength(bodyStr)
        }
      }, res => {
        let d = '';
        res.on('data', c => d += c);
        res.on('end', () => {
          let parsed;
          try { parsed = JSON.parse(d); } catch(e) { parsed = null; }
          resolve({ status: res.statusCode, data: parsed, raw: d, headers: res.headers });
        });
      });
      req.on('error', reject);
      req.write(bodyStr);
      req.end();
    });

    if (result.status === 200 && result.data?.choices?.[0]?.message?.content) return result.data;
    if (result.status === 429 || result.status === 503) {
      const retryAfter = result.headers?.['retry-after'];
      const waitMs = retryAfter ? parseInt(retryAfter, 10) * 1000 : Math.max(5000, Math.pow(2, attempt) * 2000);
      if (attempt < maxRetries) { await new Promise(r => setTimeout(r, waitMs)); continue; }
    }
    if (result.status >= 500 && attempt < maxRetries) { await new Promise(r => setTimeout(r, Math.pow(2, attempt) * 2000)); continue; }
    if (attempt >= maxRetries) throw new Error(`LLM call failed after ${maxRetries + 1} attempts. Status: ${result.status}, Response: ${result.raw?.substring(0, 500)}`);
  }
}

function extractJSON(text) {
  let str = text.trim();
  // Strip code fences only if they wrap the entire response
  if (str.startsWith('```json') && str.endsWith('```')) {
    str = str.slice(str.indexOf('\n') + 1, str.lastIndexOf('```')).trim();
  }
  return str;
}

// === STEP 1: Planning AI call — get story list ===
const planMessages = [
  {
    role: 'system',
    content: `You are a game development planning assistant for the Apeiron Cipher project (Rust/Bevy ECS).\n\nGiven an epic with its SOW, break it into implementable stories. Each story should be a single PR.\n\nOutput a JSON array of story objects:\n[{"title": "short title", "description": "one-line scope summary", "order": 1, "dependsOn": []}]\n\nThe dependsOn array contains 0-indexed references to other stories in this list (by their order number).\n\nRespond with ONLY the JSON array, no other text.\n\n## GDD (excerpt)\n${gdd.substring(0, 8000)}\n\n## Project Context (excerpt)\n${projectContext.substring(0, 8000)}`
  },
  {
    role: 'user',
    content: `Epic: ${epicTitle}\n\n${epicBody}\n\n## Scoping Conversation\n${epicComments}`
  }
];

const planResponse = await callLLM(planMessages);
const planText = planResponse.choices?.[0]?.message?.content || '[]';
let storyPlan;
try {
  storyPlan = JSON.parse(extractJSON(planText));
} catch (e) {
  throw new Error(`Failed to parse story plan: ${planText}`);
}

if (!Array.isArray(storyPlan) || storyPlan.length === 0) {
  throw new Error(`Story plan is empty or invalid: ${planText}`);
}

// === STEP 2: Create stub issues for each story ===
const epicNLabel = `epic-${epicNumber}`;

// Ensure the epic-N label exists
try {
  await githubRest('POST', `/repos/${owner}/${repo}/labels`, {
    name: epicNLabel,
    color: 'c5def5',
    description: `Stories for epic #${epicNumber}`
  });
} catch (e) {
  if (!e.message.includes('422')) throw e;
}

const createdStories = [];
for (let i = 0; i < storyPlan.length; i++) {
  const story = storyPlan[i];

  // Stub body — will be replaced by the Story Detail workflow
  const stubBody = `## ${story.title}\n\n${story.description}\n\n<!-- story-detail-pending -->\n\n_Detailed acceptance criteria and technical notes are being generated..._`;

  const result = await githubRest('POST', `/repos/${owner}/${repo}/issues`, {
    title: `[Epic ${epicNumber}] ${story.title}`,
    body: stubBody,
    labels: ['story', 'status:backlog', epicNLabel]
  });

  createdStories.push({
    number: result.data.number,
    title: story.title,
    description: story.description,
    order: story.order,
    dependsOn: story.dependsOn
  });

  await new Promise(r => setTimeout(r, 500));
}

// === STEP 3: Update dependency references ===
for (const story of createdStories) {
  const depRefs = story.dependsOn.length > 0
    ? story.dependsOn.map(d => {
        const depStory = createdStories.find(s => s.order === d);
        return depStory ? `#${depStory.number}` : `story ${d}`;
      })
    : [];

  const issueData = await githubRest('GET', `/repos/${owner}/${repo}/issues/${story.number}`);
  const currentBody = issueData.data.body || '';
  const depLine = depRefs.length > 0 ? `\nDepends on: ${depRefs.join(', ')}` : '';
  const parentLine = `\n\n---\n_Parent epic: #${epicNumber}_`;
  await githubRest('PATCH', `/repos/${owner}/${repo}/issues/${story.number}`, {
    body: currentBody + depLine + parentLine
  });
  await new Promise(r => setTimeout(r, 500));
}

// === STEP 4: Update epic body with story index ===
const epicData = await githubRest('GET', `/repos/${owner}/${repo}/issues/${epicNumber}`);
const storyIndex = createdStories
  .sort((a, b) => a.order - b.order)
  .map(s => {
    const deps = s.dependsOn.length > 0
      ? ` (depends on ${s.dependsOn.map(d => { const ds = createdStories.find(cs => cs.order === d); return ds ? `#${ds.number}` : `story ${d}`; }).join(', ')})`
      : '';
    return `- #${s.number}: ${s.title} (order: ${s.order}${deps})`;
  })
  .join('\n');

await githubRest('PATCH', `/repos/${owner}/${repo}/issues/${epicNumber}`, {
  body: (epicData.data.body || '') + `\n\n## Stories\n${storyIndex}`
});

// === STEP 5: Label epic stories_created, remove sow_ready ===
try {
  await githubRest('DELETE', `/repos/${owner}/${repo}/issues/${epicNumber}/labels/${encodeURIComponent('sow_ready')}`);
} catch (e) { if (!e.message.includes('404')) throw e; }
await githubRest('POST', `/repos/${owner}/${repo}/issues/${epicNumber}/labels`, { labels: ['stories_created'] });

// Post summary comment
await githubRest('POST', `/repos/${owner}/${repo}/issues/${epicNumber}/comments`, {
  body: `## Stories Created\n\nGenerated ${createdStories.length} story stubs from this epic's SOW:\n\n${storyIndex}\n\nDetailed story content is now being generated for each story. Please review once all stories show full acceptance criteria.\n\nWhen satisfied, apply \`status:ready\` to this epic to cascade all stories to the ready queue.`
});

// === STEP 6: Output one item per story for Split In Batches ===
// Resolve dependency titles for each story
const outputItems = createdStories.map(story => {
  const depTitles = story.dependsOn.length > 0
    ? story.dependsOn.map(d => {
        const ds = createdStories.find(cs => cs.order === d);
        return ds ? ds.title : `story ${d}`;
      }).join(', ')
    : 'none';

  return {
    json: {
      storyNumber: story.number,
      storyTitle: story.title,
      storyDescription: story.description,
      storyOrder: story.order,
      dependencyTitles: depTitles,
      epicNumber,
      epicTitle,
      repoOwner: owner,
      repoName: repo,
      gdd: gdd.substring(0, 8000),
      projectContext: projectContext.substring(0, 8000),
      epicComments,
      fixedDelayMs: '5000'
    }
  };
});

return outputItems;
